// Plan execution: for each Meta-active client, emit either:
//   (a) 12 backfill chunks of 31-day windows covering the rolling last 12 months,
//       if the client has NO data yet in raw_meta_campaign_insights;
//   (b) 1 incremental item with yesterday's window, if data already exists.
//
// Chunks are 30-day each (Meta caps time_increment=1 requests at ~90 days but
// active ad accounts at ad level can return enormous payloads at that window,
// triggering 500/'service unavailable'. 30-day chunks are reliable).

const today = new Date();
const ymd = d => d.toISOString().slice(0, 10);

return $input.all().flatMap(item => {
  const c = item.json;
  const maxDate = c.max_date;
  const isEmpty = maxDate === null || maxDate === undefined || maxDate === '' || maxDate === 'null';

  if (!isEmpty) {
    // INCREMENTAL: pull yesterday only.
    const y = new Date(today);
    y.setDate(y.getDate() - 1);
    const ymdY = ymd(y);
    return [{
      json: {
        client_id: c.client_id,
        slug: c.slug,
        currency: c.currency,
        mode: 'incremental',
        chunk_label: 'yesterday',
        time_range: `{"since":"${ymdY}","until":"${ymdY}"}`
      }
    }];
  }

  // BACKFILL: 12-month rolling window, 12 chunks of 31 days each.
  const chunks = [];
  for (let i = 0; i < 12; i++) {
    const until = new Date(today);
    until.setDate(until.getDate() - (i * 31));
    const since = new Date(until);
    since.setDate(since.getDate() - 30);
    chunks.push({
      json: {
        client_id: c.client_id,
        slug: c.slug,
        currency: c.currency,
        mode: 'backfill',
        chunk_label: `chunk_${i + 1}_of_12`,
        time_range: `{"since":"${ymd(since)}","until":"${ymd(until)}"}`
      }
    });
  }
  return chunks;
});

const decode = b64 => Buffer.from(b64, 'base64').toString('utf8').trim();
const accessToken = decode($('Get access_token').first().json.payload.data);
const adAccountId = decode($('Get ad_account_id').first().json.payload.data);
const item = $('Loop over plan').item.json;

return [{ json: {
  client_id: item.client_id,
  slug: item.slug,
  currency: item.currency,
  mode: item.mode,
  chunk_label: item.chunk_label,
  time_range: item.time_range,
  access_token: accessToken,
  ad_account_id: adAccountId,
  api_version: 'v22.0'
}}];

const ctx = $('Decode secrets').first().json;
const CLIENT_ID = ctx.client_id;
const AD_ACCOUNT = ctx.ad_account_id;
const INGESTED_AT = new Date().toISOString();
const num = v => (v === null || v === undefined || v === '' ? null : Number(v));
const pick = (arr, type) => {
  if (!Array.isArray(arr)) return null;
  const row = arr.find(a => a.action_type === type);
  return row ? Number(row.value) : null;
};

// Handle BOTH shapes: wrapped {data:[...]} OR each item is a row directly.
const all = [];
for (const it of $input.all()) {
  const j = it.json;
  if (Array.isArray(j.data)) {
    for (const r of j.data) all.push(r);
  } else if (j.campaign_id) {
    all.push(j);
  }
}

return all.map(r => ({ json: {
  client_id: CLIENT_ID,
  ingested_at: INGESTED_AT,
  ingest_source: 'cron',
  ad_account_id: AD_ACCOUNT,
  campaign_id: String(r.campaign_id),
  campaign_name: r.campaign_name ?? '',
  date_start: r.date_start,
  date_stop: r.date_stop,
  spend: num(r.spend),
  impressions: num(r.impressions),
  reach: num(r.reach),
  frequency: num(r.frequency),
  clicks: num(r.clicks),
  ctr: num(r.ctr),
  cpc: num(r.cpc),
  purchases:          pick(r.actions, 'omni_purchase') ?? pick(r.actions, 'purchase'),
  purchase_value:     pick(r.action_values, 'omni_purchase') ?? pick(r.action_values, 'purchase'),
  add_to_cart:        pick(r.actions, 'add_to_cart'),
  initiate_checkout:  pick(r.actions, 'initiate_checkout'),
  landing_page_views: pick(r.actions, 'landing_page_view'),
  link_clicks:        pick(r.actions, 'link_click'),
  video_views:        pick(r.actions, 'video_view'),
  purchase_roas:      pick(r.purchase_roas, 'omni_purchase'),
  actions:       JSON.stringify(r.actions ?? []),
  action_values: JSON.stringify(r.action_values ?? []),
  payload_json:  JSON.stringify(r)
}}));

